#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <omp.h>

#include "./../main.h"
#include "./../util/timer/timer.h"

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

void kernel_cpu(par_str par_cpu,
                dim_str dim_cpu,
                box_str* box_cpu,
                FOUR_VECTOR* rv_cpu,
                fp* qv_cpu,
                FOUR_VECTOR* fv_cpu)
{
    long long time0;
    long long time1;
    long long time2;
    long long time3;
    long long time4;
    long long time5;
    long long time6;

    time0 = get_time();

    int num_threads = NUMBER_THREADS;
    if (dim_cpu.cores_arg > 0) {
        num_threads = dim_cpu.cores_arg;
    }

    time1 = get_time();

    time2 = time1;

    time3 = time2;

    time4 = get_time();

    #pragma omp parallel num_threads(num_threads)
    {
        int tx = omp_get_thread_num();
        int wtx = tx;
        fp a2 = 2.0 * par_cpu.alpha * par_cpu.alpha;

        FOUR_VECTOR rA_shared[100];
        FOUR_VECTOR rB_shared[100];
        double qB_shared[100];

        fp r2;
        fp u2;
        fp vij;
        fp fs;
        fp fxij;
        fp fyij;
        fp fzij;
        THREE_VECTOR d;

        #pragma omp for
        for (int bx = 0; bx < dim_cpu.number_boxes; bx++) {
            int first_i = box_cpu[bx].offset;
            FOUR_VECTOR* rA = &rv_cpu[first_i];
            FOUR_VECTOR* fA = &fv_cpu[first_i];

            wtx = tx;
            while(wtx < NUMBER_PAR_PER_BOX){
                rA_shared[wtx] = rA[wtx];
                wtx = wtx + num_threads;
            }
            wtx = tx;

            #pragma omp barrier

            for (int k = 0; k < (1 + box_cpu[bx].nn); k++) {
                int pointer;
                if(k == 0){
                    pointer = bx;
                }
                else{
                    pointer = box_cpu[bx].nei[k-1].number;
                }

                int first_j = box_cpu[pointer].offset;
                FOUR_VECTOR* rB = &rv_cpu[first_j];
                fp* qB = &qv_cpu[first_j];

                wtx = tx;
                while(wtx < NUMBER_PAR_PER_BOX){
                    rB_shared[wtx] = rB[wtx];
                    qB_shared[wtx] = qB[wtx];
                    wtx = wtx + num_threads;
                }
                wtx = tx;

                #pragma omp barrier

                wtx = tx;
                while(wtx < NUMBER_PAR_PER_BOX){
                    for (int j = 0; j < NUMBER_PAR_PER_BOX; j++){
                        r2 = (fp)rA_shared[wtx].v + (fp)rB_shared[j].v - DOT((fp)rA_shared[wtx], (fp)rB_shared[j]);
                        u2 = a2 * r2;
                        vij = exp(-u2);
                        fs = 2 * vij;

                        d.x = (fp)rA_shared[wtx].x - (fp)rB_shared[j].x;
                        fxij = fs * d.x;
                        d.y = (fp)rA_shared[wtx].y - (fp)rB_shared[j].y;
                        fyij = fs * d.y;
                        d.z = (fp)rA_shared[wtx].z - (fp)rB_shared[j].z;
                        fzij = fs * d.z;

                        fA[wtx].v += (double)((fp)qB_shared[j] * vij);
                        fA[wtx].x += (double)((fp)qB_shared[j] * fxij);
                        fA[wtx].y += (double)((fp)qB_shared[j] * fyij);
                        fA[wtx].z += (double)((fp)qB_shared[j] * fzij);
                    }
                    wtx = wtx + num_threads;
                }
                wtx = tx;

                #pragma omp barrier
            }
        }
    }

    time5 = get_time();

    time6 = get_time();

    printf("Time spent in different stages of GPU_CUDA KERNEL:\n");
    printf("%15.12f s, %15.12f % : GPU: SET DEVICE / DRIVER INIT\n", (float)(time1 - time0) / 1000000, (float)(time1 - time0) / (float)(time6 - time0) * 100);
    printf("%15.12f s, %15.12f % : GPU MEM: ALO\n", (float)(time2 - time1) / 1000000, (float)(time2 - time1) / (float)(time6 - time0) * 100);
    printf("%15.12f s, %15.12f % : GPU MEM: COPY IN\n", (float)(time3 - time2) / 1000000, (float)(time3 - time2) / (float)(time6 - time0) * 100);
    printf("%15.12f s, %15.12f % : GPU: KERNEL\n", (float)(time4 - time3) / 1000000, (float)(time4 - time3) / (float)(time6 - time0) * 100);
    printf("%15.12f s, %15.12f % : GPU MEM: COPY OUT\n", (float)(time5 - time4) / 1000000, (float)(time5 - time4) / (float)(time6 - time0) * 100);
    printf("%15.12f s, %15.12f % : GPU MEM: FRE\n", (float)(time6 - time5) / 1000000, (float)(time6 - time5) / (float)(time6 - time0) * 100);
    printf("Total time:\n");
    printf("%.12f s\n", (float)(time6 - time0) / 1000000);
}
